"""
MKT Original Language Commentary — Job chapters 27–29
Run: python3 scripts/zc-original-job-27-29.py

Ch 27: Job's third discourse — his oath by God (hai-'el), the maintained tummah
       (integrity), and his description of the wicked's fate (vv13-23, probably
       reflecting what the friends argue rather than Job's own conviction).
       Key: hai-'el oath formula; hemer (bitterness) / nishmat-'eloah (divine breath);
       hallilah negation; qets/gatsar vocabulary for the wicked's end.
Ch 28: The Wisdom Hymn — the most carefully structured poem in the book.
       Three movements: human mining (vv1-11), wisdom is unfindable (vv12-19),
       only God knows wisdom (vv20-28). 'enosh for mortal human; me'ayin
       (from where = from nothingness); tehom/'Abaddon as cosmic respondents;
       the conclusion: yir'at 'Adonay hi hokhmah.
Ch 29: Job's nostalgic lament for the days of divine friendship. sod (intimate
       counsel) / horef (autumn = prime of life); the vestment metaphor of
       tsedaqah/mishpat as me'il/tsanif; the lamp/light imagery; spring rain
       (malqosh) as metaphor for Job's eagerly-awaited words.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "27": {
    "1": "<p><em>Wayyosep &rsquo;iyyov se&rsquo;et mishlo</em> (Job again lifted up his <em>mashal</em> and said) &mdash; <em>nasa&rsquo;</em> = to lift/carry; <em>mashal</em> = a wisdom saying, discourse, parable, extended metaphor. The <em>mashal</em> is not merely a speech but a heightened wisdom form &mdash; an authoritative utterance with didactic weight. The same formula appears at 29:1 (<em>wayyosep &rsquo;iyyov se&rsquo;et mishlo</em>), framing chs 27&ndash;31 as one extended <em>mashal</em> block. The repetition signals that Job is still in the role of wisdom teacher, not just a sufferer complaining.</p>",
    "2": "<p><em>Hai-&rsquo;el &rsquo;asher hesar mishpati</em> (as God lives, who has denied me justice) &mdash; the <em>hai-X</em> oath formula (&ldquo;as X lives&rdquo;) is the most solemn Hebrew oath form, typically invoking YHWH or the king. Here Job swears by God even as he accuses God of the very injustice he is protesting. The verb <em>sur</em> = to turn aside/deviate &mdash; YHWH has turned aside from giving Job justice. <em>Vesha<u>d</u>dai &rsquo;asher-hemer nafshi</em> (and the Almighty who has embittered my soul) &mdash; <em>marar</em> = to be/make bitter (same root as Naomi&rsquo;s name Mara, Ruth 1:20, and the bitter herbs of Passover, Exod 12:8). Job is bitter-souled but still invoking God.</p>",
    "3": "<p><em>Ki-khol &rsquo;od nishmat-&rsquo;eloah be&rsquo;appi</em> (as long as the breath of God is in my nostrils) &mdash; <em>nishmat &rsquo;eloah</em> = the breath of God, directly echoing Gen 2:7 (<em>nishmat hayyim</em>, breath of life) where YHWH breathes into Adam&rsquo;s nostrils. Job&rsquo;s oath has a double irony: he swears by the same God who sustains his life by that very breath, even while accusing God of injustice. <em>Veruah &rsquo;eloah be&rsquo;appi</em> = &ldquo;and the spirit/breath of God in my nostrils&rdquo; &mdash; the parallel phrase reinforces the divine-origin-of-breath theology underlying Job&rsquo;s oath.</p>",
    "4": "<p><em>Im-tedabberan sefatay &rsquo;avlah</em> (if my lips should speak wickedness) &mdash; <em>&rsquo;avlah</em> = iniquity/injustice/wrongness, the quality of something morally skewed. <em>Im-yehgeh leshoni remiyyah</em> = &ldquo;if my tongue should utter deceit/treachery&rdquo; &mdash; <em>remiyyah</em> = deceit, slackness, treachery (from the root of <em>ramah</em> = to deceive). Job&rsquo;s lips and tongue form the merism of speech: neither will deviate from truthful integrity.</p>",
    "5": "<p><em>Hallilah li im-&rsquo;atsdiqet &rsquo;etkhlem</em> (God forbid that I should justify/agree you are right) &mdash; <em>hallilah</em> is a strong interjection: &ldquo;far be it from me!&rdquo; / &ldquo;God forbid!&rdquo; (used 21 times in OT for strong moral rejection). <em>&rsquo;atsdiq</em> = declare right/justify (hiphil of <em>tsadaq</em>); Job refuses to justify his friends&rsquo; position against him. <em>Im-&rsquo;agva tummati mimmenni</em> = &ldquo;I will not surrender my wholeness from me&rdquo; &mdash; <em>tummah</em> = integrity/wholeness (noun of the <em>tam</em> family, same as 1:1 and 2:3,9). The word &ldquo;surrender&rdquo; (<em>sur</em>) = turn aside, depart &mdash; he will not let his integrity be moved even by death.</p>",
    "6": "<p><em>Betsdaqati hehezaqti velo-&rsquo;arpennah</em> (I hold fast to my righteousness and will not release it) &mdash; <em>tsedaqah</em> = righteousness (noun form, distinct from the adjective <em>tsaddiq</em>). <em>hazaq</em> = to hold fast, grip firmly (the same verb as Job&rsquo;s wife&rsquo;s rhetorical question at 2:9, <em>hahaziq betummatekha</em>). <em>Lo-yihrap levavi miyamay</em> = &ldquo;my heart does not reproach me for any of my days&rdquo; &mdash; <em>harap</em> = to reproach, taunt (pi&rsquo;el). Job&rsquo;s conscience (<em>lev</em> = heart, the seat of inner knowledge) is clear for every day of his life.</p>",
    "7": "<p><em>Yehiy ke-rasha&rsquo; &rsquo;oyevi</em> (let my enemy be as/like the wicked) &mdash; jussive form, an imprecatory wish. Job invokes the fate he is about to describe (the wicked man&rsquo;s doom, vv8&ndash;23) on those who oppose him. The friends argue that Job&rsquo;s suffering proves his wickedness; Job turns the argument: let those who falsely accuse him receive the lot they attribute to the wicked. The imprecation is not vengeance but the inversion of the friends&rsquo; logic.</p>",
    "8": "<p><em>Ki mah-tiqwat hanef ki-yivtsa&rsquo;</em> (what hope does the godless one have when God cuts him off?) &mdash; <em>hanef</em> = the godless/profane person (from <em>hanap</em> = to be polluted, pollute; applied to land, people, speech). <em>ki-yivtsa&rsquo; &rsquo;eloah nafsho</em> = &ldquo;when God extracts/cuts off his soul&rdquo; &mdash; <em>batsa&rsquo;</em> = to cut off, extract (as cutting a root or stopping a flow); the image of God cutting the thread of the godless person&rsquo;s life. The godless man&rsquo;s hope is zero at the moment of divine cutting-off.</p>",
    "9": "<p><em>Hatsaqato yishma&rsquo; &rsquo;el</em> (will God hear his cry?) &mdash; <em>tsaqah</em> = to cry out (the cry of the oppressed that reaches God, Exod 3:7; Neh 5:1; Job 34:28). The godless man&rsquo;s lack of covenant relationship means his cry does not have the standing to reach God. <em>Ki tavo &rsquo;alav tsarah</em> = &ldquo;when trouble comes upon him&rdquo; &mdash; the godless can only expect that his trouble-cry falls into deaf cosmic ears, because he has not cultivated the relationship that gives the cry its standing.</p>",
    "10": "<p><em>Im-&rsquo;al-shaddai ya&rsquo;ang</em> (does he delight in the Almighty?) &mdash; <em>&rsquo;anag</em> = to be soft/delicate, to take delight in (only a few occurrences; cf. Ps 37:4, <em>hit&rsquo;anag &rsquo;al-YHWH</em> = delight yourself in YHWH). <em>yiqra&rsquo; &rsquo;eloah bekhol-&rsquo;et</em> = &ldquo;does he call on God at all times?&rdquo; &mdash; the two marks of genuine piety that the godless lack: delight in the Almighty and constant prayer. Both are marks Job himself displayed (1:1,5), which is why his prayers and cries have standing where the godless person&rsquo;s do not.</p>",
    "11": "<p><em>&rsquo;Orekh bi yad-&rsquo;el</em> (I will instruct you about the hand of God) &mdash; the verb is <em>yarah</em> (hiphil) = to throw/shoot/direct &mdash; the same root as <em>Torah</em> (teaching/direction). Job positions himself as a teacher of divine wisdom; the &ldquo;hand of God&rdquo; (<em>yad-&rsquo;el</em>) is the metaphor for God&rsquo;s active power and governance in history. <em>&rsquo;asher im-shaddai lo-&rsquo;akhahed</em> = &ldquo;what is with the Almighty I will not hide&rdquo; &mdash; the verb <em>khahad</em> = to hide/conceal (pi&rsquo;el). Job claims a kind of prophetic boldness: he will not conceal what he has seen of God&rsquo;s ways.</p>",
    "12": "<p><em>Hen-&rsquo;attem kullekem hazitem</em> (you yourselves have all seen/beheld it) &mdash; <em>hazah</em> = to see, behold (often of prophetic/visionary seeing, more intensive than the ordinary <em>ra&rsquo;ah</em>). Job charges the friends with willful selective blindness: they have seen the same evidence as Job but draw convenient conclusions. <em>Vema-zeh hevel tehbalu</em> = &ldquo;why then have you become so thoroughly vain/empty?&rdquo; &mdash; <em>hevel</em> = breath/vapor/vanity (the key word of Ecclesiastes, used 38 times there). The friends&rsquo; wisdom has devolved to <em>hevel</em> &mdash; empty, meaningless, like a puff of breath.</p>",
    "13": "<p><em>Zeh-heleq-&rsquo;adam ra&rsquo;sha&rsquo; me-&rsquo;el</em> (this is the lot of the wicked from God) &mdash; <em>heleq</em> = portion, lot (the share assigned to someone). The description of the wicked&rsquo;s fate in vv13&ndash;23 is linguistically and theologically close to what the friends have argued throughout. Many commentators consider this section to have been accidentally relocated from a friend&rsquo;s speech, or to represent Job presenting his opponents&rsquo; argument before refuting it. <em>venahalt &rsquo;aritsim yiqqahu mishaddai</em> = &ldquo;and the inheritance of oppressors they receive from the Almighty&rdquo; &mdash; <em>&rsquo;aritsim</em> = tyrants/oppressors (from <em>&rsquo;arats</em> = to terrify, inspire dread).</p>",
    "14": "<p><em>Im-yirbu vanav le-harev</em> (if his children multiply, it is for the sword) &mdash; the multiplication of children (normally a sign of blessing, Gen 22:17; Ps 128:3) becomes a multiplication of victims. <em>Vetse&rsquo;etsa&rsquo;av lo-yisbe&rsquo;u-lahem</em> = &ldquo;his descendants will not be satisfied with bread&rdquo; &mdash; <em>tsotse&rsquo;et</em> = offspring (a rare form, also in Isa 22:24). The wicked&rsquo;s family suffers the consequences of his deeds.</p>",
    "15": "<p><em>Seridav bammavet yiqberu</em> (his survivors will be buried by death/plague) &mdash; <em>serid</em> = survivor, remnant. <em>Mavet</em> = death, or possibly a disease-demon (the Ugaritic Mot, death personified). <em>Ve&rsquo;almanotav lo-tivkeyyna</em> = &ldquo;and his widows will not weep for them&rdquo; &mdash; the absence of mourning is a sign of ultimate disgrace in the ancient Near East (cf. Jer 22:18 for the fate of those denied mourning).</p>",
    "16": "<p><em>&rsquo;Im-yitspor ke&rsquo;afar kesep</em> (though he pile up silver like dust) &mdash; <em>tsaphar</em> = to pile up, heap. The comparison of silver (<em>kesep</em>) to dust (<em>afar</em>) emphasizes the quantitative abundance; so much silver it becomes as cheap and plentiful as dust. <em>Vekikhomer yakhim levush</em> = &ldquo;and lay up clothing as plentiful as clay&rdquo; &mdash; <em>khomer</em> = clay, mud (the building material as cheap as dirt); clothing stored in such abundance it is like a pile of clay.</p>",
    "17": "<p><em>Yakhim vetsaddiq yilbash</em> (he may prepare it but the righteous will wear it) &mdash; the wicked man is the inadvertent benefactor of the righteous. <em>Vekhesep naqqi yehaleq</em> = &ldquo;and the innocent will share out the silver&rdquo; &mdash; the accumulated wealth of the wicked will be redistributed to the innocent by divine reversal. This is the Deuteronomic principle of possessing the property of the defeated wicked (Deut 6:10&ndash;11).</p>",
    "18": "<p><em>Banah kea&rsquo;ash beito</em> (he builds his house like a moth builds) &mdash; the <em>ash</em> (moth) builds its cocoon, which is destroyed at a touch. <em>Ukhesuka &rsquo;asah note</em> = &ldquo;and like the shelter (<em>sukkah</em>) a watchman puts up&rdquo; &mdash; <em>sukkah</em> = a temporary booth/shelter (the same word as the Feast of Booths); the watchman&rsquo;s field shelter is deliberately temporary, built to be abandoned. The wicked man&rsquo;s house, however grand, is actually a moth-cocoon or a harvest-booth: structurally temporary, destined for dissolution.</p>",
    "19": "<p><em>&rsquo;Ashir yishkav velo-ye&rsquo;asef</em> (the rich man lies down but is not gathered) &mdash; <em>ne&rsquo;esaf &rsquo;el-&rsquo;ammav</em> (gathered to his people) is the standard Hebrew expression for a peaceful, honored death and burial among family (Gen 25:8; 35:29; 49:33). The negation: the wicked rich man lies down in death but is not gathered &mdash; denied the dignified death of the righteous. <em>Yifqah &rsquo;enav ve&rsquo;einennu</em> = &ldquo;he opens his eyes and he is gone&rdquo; &mdash; one blink of waking and the man is erased.</p>",
    "20": "<p><em>Tassigehu kemayim ballahot</em> (terrors overtake him like a flood) &mdash; <em>nasag</em> (hiphil) = to overtake, reach; <em>ballahot</em> = terrors (from <em>balal</em> = to terrify). <em>Laylah genavathu sufah</em> = &ldquo;in the night a storm steals him away&rdquo; &mdash; <em>ganav</em> = to steal (the same root as the vision stealing in 4:12, where Eliphaz said the revelation &ldquo;stole&rdquo; to him). The wicked man is stolen in the night, as suddenly as a thief enters.</p>",
    "21": "<p><em>Yis&rsquo;ahu qadim vayelekh</em> (the east wind sweeps him away and he goes) &mdash; <em>qadim</em> = the east wind, the hot, destroying wind of the Levant (<em>sirocco</em>), associated with YHWH&rsquo;s judgment (Exod 14:21; Ezek 17:10). <em>Visarhu mimmiqomo</em> = &ldquo;and it hurls him from his home&rdquo; &mdash; <em>sara&rsquo;</em> = to blow away, toss, scatter. The east wind that gave Job his initial disaster (1:19, &ldquo;a great wind from the wilderness&rdquo;) reappears here as the wicked man&rsquo;s destroyer.</p>",
    "22": "<p><em>Veyashlekh &rsquo;alav velo-yahemol</em> (for God hurls his power at him without mercy) &mdash; <em>shalakh</em> = to throw, hurl (God as the one who hurls against the wicked). <em>Lo-yahemol</em> = without pity (the verb <em>hamal</em> = to spare, have compassion; negated here). <em>Baroah yivrah miyaddo</em> = &ldquo;he flees desperately from his hand&rdquo; &mdash; the wicked man&rsquo;s futile flight from the divine assault.</p>",
    "23": "<p><em>Yispoq &rsquo;alav kappayim</em> (men clap their hands at him) &mdash; the hand-clapping here is not applause but the gesture of derision or astonishment (cf. Lam 2:15; Ezek 25:6 where clapping of hands = contempt). <em>Veyisroq &rsquo;alav mimqomo</em> = &ldquo;and hisses him from his home&rdquo; &mdash; <em>saraq</em> = to whistle/hiss (a gesture of contempt, Jer 19:8; Zeph 2:15). The wicked man&rsquo;s departure from his home is marked by public contempt: clapping and hissing, the sounds of dismissal.</p>"
  },
  "28": {
    "1": "<p><em>Ki yesh lakesef motsa&rsquo;</em> (surely silver has its mine/source) &mdash; <em>motsa&rsquo;</em> = outgoing, source, point of exit &mdash; the vein of ore from which silver emerges. <em>Vemaqom lazahav yazeqqu</em> = &ldquo;and a place for gold where they refine it&rdquo; &mdash; <em>zaqaq</em> = to refine by filtering/straining (the pi&rsquo;el intensive). The chapter opens with the premise that human technology can locate and extract every precious mineral from the earth &mdash; a premise that will be systematically applied and then overturned for the one substance (wisdom) that defeats human mining.</p>",
    "2": "<p><em>Barzel me&rsquo;afar yuqqah</em> (iron is taken from the earth/dust) &mdash; <em>afar</em> = dust/earth (the same word as Adam&rsquo;s origin, Gen 2:7). <em>Ve&rsquo;even yatsaq nehushah</em> = &ldquo;and from the ore-stone copper is smelted&rdquo; &mdash; <em>yatsaq</em> = to pour/cast/smelt; <em>nehushah</em> = copper/bronze. The smelting of copper from ore requires the same principle: the precious metal is hidden in and extractable from the matrix of common stone.</p>",
    "3": "<p><em>Qets sam lahoshekh</em> (he sets a limit/end to the darkness) &mdash; <em>qets</em> = end, limit, terminus; <em>lahoshekh</em> = the darkness of the mine shaft. The miner&rsquo;s lamp penetrates what was dark, setting a boundary on darkness by pushing it back. <em>Uvekhol-takhlit hu hhoqer</em> = &ldquo;and to every extremity he searches&rdquo; &mdash; <em>takhlit</em> = the uttermost limit. <em>&rsquo;Even &rsquo;ofel vetsalmavet</em> = &ldquo;the stone of gloom and deep shadow&rdquo; &mdash; the deepest, darkest rock that no natural light reaches.</p>",
    "4": "<p><em>Parats nahal me&rsquo;im-gar</em> (far from where people live a shaft is opened/broken) &mdash; <em>parats</em> = to burst/break through; <em>nahal</em> = a wadi/stream-channel or, here, a mine shaft cut through the rock. <em>Nishkahim min-ragel</em> = &ldquo;forgotten by the foot&rdquo; &mdash; <em>nishkah</em> = forgotten (niphal of <em>shakah</em>). The mine shafts run directly beneath surfaces where people walk, completely unknown to those feet above. <em>Dallum me&rsquo;enosh nau&rsquo;u</em> = &ldquo;far from mortals they dangle and sway&rdquo; &mdash; the miners hanging in shafts far below, remote from human society.</p>",
    "5": "<p><em>&rsquo;Erets mimmenah yetse&rsquo;-lahem</em> (the earth &mdash; from it bread comes out) &mdash; the contrast: the surface produces agricultural food (<em>lahem</em> = bread/food); <em>vetahteyha nehepakh ke&rsquo;esh</em> = &ldquo;but underneath it is turned up as though by fire&rdquo; &mdash; the violent transformation of rock by mining (or possibly volcanic imagery). The same earth that produces nourishing bread on its surface is being burned and turned upside down underneath.</p>",
    "6": "<p><em>Meqom-sappirim &rsquo;avaneha</em> (its stones are the source of sapphires) &mdash; <em>sappirim</em> = sapphires/lapis lazuli (the dark blue stone associated with YHWH&rsquo;s throne, Exod 24:10; Ezek 1:26). <em>Ve&rsquo;afrot zahav lo</em> = &ldquo;and it contains flakes of gold&rdquo; &mdash; <em>afrot</em> = dust/fine flakes; gold dust embedded in the rock. The earth contains all these treasures but keeps them hidden &mdash; requiring the labor of breaking in to find them.</p>",
    "7": "<p><em>Netiv lo-yeda&rsquo;o &rsquo;ayit</em> (a path no bird of prey knows) &mdash; <em>&rsquo;ayit</em> = a bird of prey (hawk, vulture; the term for a bird with the sharpest possible vision, used to emphasize the imperceptibility of the mine paths). <em>Velo shezafattu &rsquo;ein ha-dayya</em> = &ldquo;nor has the eye of the falcon observed it&rdquo; &mdash; <em>dayya</em> = a falcon/kite. Even the keenest vision in the natural world cannot discern the path to the mine.</p>",
    "8": "<p><em>Lo-hidrukhuhu benei-shahhats</em> (the proud/fierce beasts have not walked it) &mdash; <em>benei-shahhats</em> = literally &ldquo;sons of pride&rdquo; &mdash; the powerful wild animals (lions). <em>Velo &rsquo;avhar &rsquo;alav shahal</em> = &ldquo;nor has the fierce lion passed over it&rdquo; &mdash; <em>shahal</em> = a young roaring lion. Even the most powerful predators do not know the path to the mining depths. The chapter constructs an argument by escalation: the birds with sharpest vision and the beasts with greatest power are equally ignorant of this path.</p>",
    "9": "<p><em>Baseles shalah yado</em> (he puts his hand to the flint/hard rock) &mdash; <em>seles</em> = flint, the hardest rock (used for cutting implements in ancient technology). <em>Hapakh mishores harim</em> = &ldquo;he overturns mountains from their roots/foundations&rdquo; &mdash; <em>hapakh</em> = to overturn, turn upside down (a strong verb of radical inversion; used of Sodom&rsquo;s overthrow, Gen 19:25). Human technology is powerful enough to uproot mountains in the search for ore.</p>",
    "10": "<p><em>Bayurot &rsquo;avot yeqaq</em> (he cuts channels through the rocks) &mdash; <em>yeqaq</em> = cuts/hews; channels (<em>yurot</em>) cut through solid rock to allow access. <em>Vekhol-yaqar ra&rsquo;atah &rsquo;eyno</em> = &ldquo;and everything precious his eye sees&rdquo; &mdash; the miner&rsquo;s eye systematically takes in every precious thing (<em>yaqar</em> = precious, rare, honored) that the opened rock reveals.</p>",
    "11": "<p><em>Mibeki neharot hibesh</em> (he holds back the springs/streams from flowing) &mdash; <em>beki</em> = weeping/trickling (used for tears; here for trickling water in underground streams). <em>Vatatsafun yotsi&rsquo; or</em> = &ldquo;and brings hidden things out to the light&rdquo; &mdash; <em>tsafun</em> = what is hidden/buried (from <em>tsafan</em> = to hide/treasure). The miner controls water flow and brings what was hidden to light. This verse is the peak of human technological achievement in the hymn &mdash; the turning point before the &ldquo;but where shall wisdom be found?&rdquo; of v12.</p>",
    "12": "<p><em>Veha-hokhmah me&rsquo;ayin timmatse&rsquo;</em> (but wisdom &mdash; from where shall it be found?) &mdash; the rhetorical pivot of the entire chapter. <em>me&rsquo;ayin</em> = from where? &mdash; literally &ldquo;from what nothingness?&rdquo; (<em>&rsquo;ayin</em> = nothingness, the absence). Wisdom is being sought like a mine location, but no map or technology can locate it. <em>Ve&rsquo;ey zeh maqom binah</em> = &ldquo;and what is the place of understanding?&rdquo; &mdash; <em>maqom</em> = place, site; <em>binah</em> = discernment/understanding (from <em>bin</em> = to distinguish, see between). If the chapter just proved that every precious mineral has a <em>maqom</em> (v1&ndash;11), wisdom has no <em>maqom</em> that human exploration can find.</p>",
    "13": "<p><em>Lo-yada&rsquo; &rsquo;enosh &rsquo;erkah</em> (no mortal knows its worth/way to it) &mdash; <em>&rsquo;enosh</em> = frail mortal human (chosen over <em>&rsquo;ish</em> or <em>adam</em> to emphasize human limitation). <em>&rsquo;erkah</em> = its ordering/worth/path (from <em>&rsquo;arak</em> = to arrange, evaluate). The double meaning: no mortal knows wisdom&rsquo;s value (cannot price it) and no mortal knows its arrangement (cannot find its location). <em>Velo timmatse&rsquo; be&rsquo;erets hahayyim</em> = &ldquo;and it is not found in the land of the living&rdquo; &mdash; the land of the living (<em>&rsquo;erets hahayyim</em>) is the domain where human searching operates; wisdom is not there.</p>",
    "14": "<p><em>Tehom &rsquo;amar lo-vi hi&rsquo;</em> (the Deep says &ldquo;it is not in me&rdquo;) &mdash; <em>tehom</em> = the primordial cosmic deep (Gen 1:2; Ps 42:7; 104:6), personified as a cosmic voice in this passage. <em>Veyam &rsquo;amar &rsquo;ein imadi</em> = &ldquo;and the Sea says &lsquo;it is not with me&rsquo;&rdquo; &mdash; both the Deep and the Sea (<em>yam</em>) speak, searching their own depths and reporting wisdom&rsquo;s absence. The cosmic realms that dwarf human experience are themselves ignorant of wisdom&rsquo;s location.</p>",
    "15": "<p><em>Lo-yutan segor tahteyha</em> (pure gold cannot be given/paid for it) &mdash; <em>segor</em> = closed/refined gold, a gold bar (from <em>sagar</em> = to close/shut). <em>Velo-yishaqel kesep mehirah</em> = &ldquo;nor can silver be weighed out as its price&rdquo; &mdash; <em>shaqal</em> = to weigh (same root as <em>shekel</em>, the standard weight-unit of silver). The chapter shifts from geography (where?) to commerce (what price?): wisdom cannot be located geographically or purchased commercially.</p>",
    "16": "<p><em>Lo-tesulleh bektem-&rsquo;ofir</em> (it cannot be matched/valued against the gold of Ophir) &mdash; <em>sulleh</em> (pu&rsquo;al of <em>salah</em>) = to be weighed/valued. <em>Ktem-&rsquo;ofir</em> = the gold of Ophir, the finest gold known in the ancient world (1 Kgs 9:28; Ps 45:9; Isa 13:12). <em>Beshoham yaqar veesappir</em> = &ldquo;against the precious onyx and sapphire&rdquo; &mdash; the most precious gems of the ancient Near East are insufficient as equivalent value for wisdom.</p>",
    "17": "<p><em>Lo-ya&rsquo;arkennah zahav veukhukhit</em> (gold and glass/crystal cannot equal its value) &mdash; <em>&rsquo;arakh</em> = to arrange, compare, be equal to (same root as <em>&rsquo;erkah</em> in v13). <em>ukhukhit</em> = glass/crystal (probably fine transparent glass, which was extremely valuable in the ancient world). <em>Utemurat ah yeraqah fine gold</em> = &ldquo;its exchange cannot be in items of fine gold&rdquo; &mdash; the fine gold jewelry is insufficient for the trade.</p>",
    "18": "<p><em>Ram vegalit lo yizkker</em> (coral and crystal are not worth mentioning) &mdash; <em>ram</em> = coral (from the sea floor, expensive and exotic); <em>galit</em> = crystal or pearl (uncertain). <em>Vemeshekh hokhmah mippeninim</em> = &ldquo;the acquisition of wisdom is above rubies&rdquo; &mdash; <em>meshekh</em> = drawing/pulling out (the effort of obtaining something valuable); <em>peninim</em> = red coral, rubies, or pearls (cf. Prov 3:15; 31:10 where a capable wife is worth more than <em>peninim</em>). The comparison to Prov 3:15 and 31:10 places this wisdom hymn within the Solomonic-wisdom tradition.</p>",
    "19": "<p><em>Lo-yesawennah pitdat-kush</em> (the topaz of Cush cannot compare with it) &mdash; <em>pitdah</em> = topaz (Exod 28:17, in the high priest&rsquo;s breastplate). <em>Cush</em> = Ethiopia/Nubia, the source of the finest topaz. <em>Bektem tahor lo te&rsquo;arakh</em> = &ldquo;against pure gold it cannot be priced&rdquo; &mdash; the culmination of the commercial inventory. Every precious material that human commerce knows &mdash; gold (various grades), silver, sapphire, onyx, glass, coral, ruby, topaz &mdash; is explicitly declared insufficient to purchase wisdom.</p>",
    "20": "<p><em>Veha-hokhmah me&rsquo;ayin tavo&rsquo;</em> (where then does wisdom come from?) &mdash; the rhetorical question is repeated from v12 (nearly verbatim: <em>timmatse&rsquo;</em> = be found → <em>tavo&rsquo;</em> = come). The second question is slightly different: not &ldquo;where is it found?&rdquo; but &ldquo;where does it come from?&rdquo; The change of verb (<em>ba&rsquo;</em> = to come/arrive) shifts the focus from location to source. <em>Ve&rsquo;ey zeh maqom binah</em> = the exact repetition of v12b, bracketing the commercial inventory as a literary bracket.</p>",
    "21": "<p><em>Venilmah me&rsquo;einei kol-hay</em> (it is hidden from the eyes of every living creature) &mdash; <em>nilmah</em> = it is concealed (niphal of <em>&rsquo;alam</em> = to hide, conceal; cf. Job 6:10 where Job says he has not concealed the Holy One&rsquo;s words). <em>Umippof hashsayim nisteirah</em> = &ldquo;and hidden from the bird of the heavens&rdquo; &mdash; the birds of the sky (who had the keenest vision in v7) are equally in the dark. The living world, from earth-dwelling animals to the flying birds, is universally ignorant of wisdom&rsquo;s location.</p>",
    "22": "<p><em>&rsquo;Abaddon vamavet &rsquo;ameru</em> (Abaddon and Death say) &mdash; <em>&rsquo;Abaddon</em> = the place of destruction, the realm of the dead (from <em>&rsquo;abad</em> = to perish; appears only in Job, Proverbs, and Psalms in the OT; later used in Rev 9:11 as the name of the angel of the abyss). The personification of both the cosmic deep (v14) and the realm of the dead speaks: even Sheol&rsquo;s rumor-network (&ldquo;we have heard a whisper&rdquo;) only catches rumors of wisdom, not its location. The universal ignorance spans from the living world to the dead.</p>",
    "23": "<p><em>&rsquo;Elohim hevin darkah</em> (God understands the way to it) &mdash; the resolution of the chapter&rsquo;s search: only God (<em>&rsquo;elohim</em>) has wisdom&rsquo;s <em>derek</em> (way, path). <em>Vehu yada&rsquo; et-meqomah</em> = &ldquo;and he knows its location&rdquo; &mdash; <em>maqom</em> (place) finally finds its answer: God knows it. The mining metaphor is resolved: God is the only mining engineer who knows the vein location. He has been seeking wisdom in the wrong direction &mdash; it cannot be extracted by human technology; it can only be given by the one who knows its location.</p>",
    "24": "<p><em>Ki-hu liknot ha&rsquo;arets yabbit</em> (for he looks to the ends of the earth) &mdash; God&rsquo;s cosmic vision spans the entire created order. <em>Tahat kol-hashamayim yir&rsquo;eh</em> = &ldquo;and sees everything under all of heaven&rdquo; &mdash; the scope is total: every point under the sky is within God&rsquo;s field of vision. Only such cosmic omnivision could know where wisdom is hidden when even the Deep, the Sea, and Abaddon report ignorance.</p>",
    "25": "<p><em>La&rsquo;asot laruah mishqal</em> (when he assigned a weight to the wind) &mdash; <em>mishqal</em> = weight (same root as <em>shaqal</em> = to weigh, and <em>shekel</em>). YHWH weighs the wind &mdash; a remarkable image of divine precision over the seemingly uncontrollable. <em>Vemayim tikken bemiddah</em> = &ldquo;and measured the waters by measure&rdquo; &mdash; <em>tikken</em> = he established/measured (from <em>taqan</em> = to set right, measure). God&rsquo;s precision over wind and water contrasts with the ungovernable appearance of weather.</p>",
    "26": "<p><em>Beasoto lematar hoq</em> (when he made a decree for the rain) &mdash; <em>hoq</em> = statute, decree, appointed limit (the word for laws inscribed in stone). YHWH gave the rain (<em>matar</em>) a decree that governs it, like a legal statute. <em>Vedderekh lahaziz qolot</em> = &ldquo;and a path for the lightning and thunder&rdquo; &mdash; the storms are not chaotic but follow <em>derekh</em> (a path, a way) that God has established. The same vocabulary used for wisdom (&ldquo;where is wisdom&rsquo;s <em>derek</em>?&rdquo; v23) appears here: the storms have a <em>derek</em> because God gave it; wisdom has its <em>derek</em> for the same reason.</p>",
    "27": "<p><em>&rsquo;Az ra&rsquo;ah vayesapperah</em> (then he saw it and made it known/declared it) &mdash; <em>saphar</em> = to count/number/declare (root of <em>sefer</em> = book, and <em>mispar</em> = number). God sees wisdom and &ldquo;tells&rdquo; it &mdash; numbers it, declares it, records it. <em>Hekhinah vegam-haqarah</em> = &ldquo;he established it and fully searched it out&rdquo; &mdash; <em>kun</em> = to establish, make firm; <em>haqar</em> = to search/probe thoroughly (same word used of the friends who &ldquo;searched&rdquo; Job in 29:16). God has already done the full investigation of wisdom; it does not remain to be found by human searching because it has already been found, established, and declared by God.</p>",
    "28": "<p><em>Vayyomer le&rsquo;adam</em> (and he said to mankind) &mdash; this is the chapter&rsquo;s resolution. After establishing that only God knows wisdom&rsquo;s location, God communicates to <em>&rsquo;adam</em> (humanity, generic) the accessible form of wisdom. <em>Hen yir&rsquo;at &rsquo;adonay hi hokhmah</em> = &ldquo;look &mdash; the fear of the Lord is wisdom&rdquo; &mdash; <em>yir&rsquo;ah</em> = fear/reverence. The same four-descriptor of Job in 1:1 ended with <em>yare&rsquo; &rsquo;elohim</em> (fearing God); the wisdom hymn concludes that this very fear is the wisdom that is inaccessible to human mining but accessible through relationship with God. <em>Vesur mera&rsquo; binah</em> = &ldquo;and to turn from evil is understanding&rdquo; &mdash; the same phrase that described Job at the book&rsquo;s opening (<em>sar mera&rsquo;</em>, 1:1). The conclusion of the greatest wisdom poem in the OT is: Job already has wisdom; he is defined by the qualities the hymn names as wisdom.</p>"
  },
  "29": {
    "1": "<p><em>Wayyosep &rsquo;iyyov se&rsquo;et mishlo</em> (Job again continued his discourse) &mdash; the same formula as 27:1, confirming that chs 27&ndash;31 form a single extended <em>mashal</em> unit. Chapter 29 begins Job&rsquo;s nostalgic lament for the days before his suffering. The speech covers three movements: the former blessing (ch29), the present suffering (ch30), and the oath of innocence (ch31). Chapter 29 is the OT&rsquo;s most extended first-person portrait of righteous social leadership.</p>",
    "2": "<p><em>Mi-yiteneni kiyarhe-qedem</em> (oh that I were as in the months of old) &mdash; <em>mi-yiteneni</em> = &ldquo;who will give to me&rdquo; = the formula of longing/wish (&ldquo;oh that...!&rdquo;). <em>Yarhe-qedem</em> = months of <em>qedem</em> (the past, antiquity, the east direction associated with origins). <em>Kimei &rsquo;elohah yishmereni</em> = &ldquo;in the days when God watched over me&rdquo; &mdash; <em>shamar</em> = to keep, guard, watch over (the verb of the Aaronic blessing: YHWH &ldquo;keep you,&rdquo; Num 6:24). Job remembers divine watchfulness as blessing; now he experiences it (in his suffering) as curse.</p>",
    "3": "<p><em>Behillo nero &rsquo;alei ro&rsquo;shi</em> (when his lamp shone over my head) &mdash; <em>nerot</em> = lamp; <em>hilo</em> = its shining (infinitive of <em>halal</em> = to shine/praise). The lamp over the head is the divine light of favor and guidance (Ps 18:28: &ldquo;you light my lamp&rdquo;; Ps 119:105: &ldquo;your word is a lamp to my feet&rdquo;). <em>Ve&rsquo;or-lo elek-hoshekh</em> = &ldquo;and by his light I walked through darkness&rdquo; &mdash; the darkness (<em>hoshekh</em>) was navigated by divine light. This verse is the inversion of Job&rsquo;s current experience: now he walks in darkness with no lamp.</p>",
    "4": "<p><em>Ka&rsquo;asher hayiti bimei horpi</em> (as I was in the days of my autumn/prime) &mdash; <em>horef</em> = autumn/harvest season (the most productive season of the agricultural year). Job&rsquo;s prime of life is described as his &ldquo;autumn&rdquo; &mdash; the season of maximum fruit, maturity, and harvest. <em>Besod &rsquo;eloah &rsquo;ali &rsquo;ahali</em> = &ldquo;when the friendship/counsel of God was over my tent&rdquo; &mdash; <em>sod</em> = intimate circle, secret counsel, confidential gathering (Ps 25:14: &ldquo;the <em>sod</em> of YHWH is for those who fear him&rdquo;; Jer 23:18: &ldquo;who has stood in the <em>sod</em> of YHWH?&rdquo;). Job remembers being in YHWH&rsquo;s inner circle of counsel &mdash; the most intimate form of divine relationship.</p>",
    "5": "<p><em>Besod &rsquo;adonay yesaret shaddai &rsquo;imadi</em> (when the Almighty was still with me) &mdash; <em>&rsquo;imadi</em> = with me (the divine presence with the person). <em>Vesevivotay ne&rsquo;aray</em> = &ldquo;when my children were around me&rdquo; &mdash; the children who were killed in ch1 are remembered as surrounding Job in his former prosperity. The contrast is acute: the children who circled Job in happiness now lie dead.</p>",
    "6": "<p><em>Birhots halikkay behemath</em> (when I bathed my steps in cream/curds) &mdash; <em>rahas</em> = to wash/bathe; <em>hemath</em> = curds/cream/butter (the product of cows, here used for extreme agricultural abundance). <em>Vetsur yatsaq &rsquo;imadi palgei-shamen</em> = &ldquo;and the rock poured out for me streams of olive oil&rdquo; &mdash; <em>palgei shamen</em> = streams of oil. The image of oil flowing from solid rock echoes Deut 32:13 (<em>yinqehu shemen mehalhammish tsur</em> = &ldquo;they sucked oil from the flinty rock&rdquo;). The abundance is so extreme that rock itself pours oil &mdash; the most infertile substrate becomes a source of the most precious agricultural product.</p>",
    "7": "<p><em>Betseti sha&rsquo;ar &rsquo;alei-qaret</em> (when I went out to the gate over the city) &mdash; <em>sha&rsquo;ar</em> = the city gate, the site of judicial proceedings, commercial transactions, and social meeting in the ancient Israelite/Near Eastern city (Deut 22:15; Ruth 4:1; Amos 5:10). <em>Barehov &rsquo;akhinu moshavi</em> = &ldquo;when I prepared/set my seat in the public square&rdquo; &mdash; <em>rehhov</em> = the broad open square near the gate; <em>mokhehin</em> = I set/prepared (from <em>kun</em>). Job took his judicial seat in the city&rsquo;s public space &mdash; the position of the judge and leader.</p>",
    "8": "<p><em>Ra&rsquo;uni ne&rsquo;arim venikhba&rsquo;u</em> (the young men saw me and stepped aside/hid themselves) &mdash; <em>nikba&rsquo;u</em> = hid themselves, stepped back (niphal of <em>khaba&rsquo;</em> = to hide). The young men&rsquo;s retreat was a gesture of deference, not fear. <em>Veqenim qamu &rsquo;amadu</em> = &ldquo;and the aged rose and stood to their feet&rdquo; &mdash; the elders (<em>qenim</em> = aged men) rising in respect is a gesture of honor that the ancient world required for leaders and sages (Lev 19:32: &ldquo;rise before the gray head&rdquo;).</p>",
    "9": "<p><em>Sarim &rsquo;atseru bimillim</em> (princes held back their words) &mdash; <em>sarim</em> = princes/officials; <em>&rsquo;atsaru</em> = restrained, held back (from <em>&rsquo;atsar</em> = to restrain). The highest social class &mdash; the princes &mdash; fell silent before Job&rsquo;s wisdom. <em>Vekhaf yasimmu lefiyhem</em> = &ldquo;and put their hand over their mouth&rdquo; &mdash; the gesture of respectful silence in the presence of greater wisdom (Job 40:4 where Job himself will make this gesture before YHWH from the whirlwind).</p>",
    "10": "<p><em>Qol negidim nistatar</em> (the voice of the nobles was hidden/fell silent) &mdash; <em>nagid</em> = a leader, ruler, commander (used of David as the designated king before his coronation, 1 Sam 25:30). <em>Uleshon lehekhham davaqah</em> = &ldquo;and their tongue stuck to the roof of their mouths&rdquo; &mdash; <em>davaq</em> = to cling, stick to (the same verb as Ruth 1:14, &ldquo;Ruth clung to her mother-in-law&rdquo;). Complete, involuntary silence before Job&rsquo;s presence.</p>",
    "11": "<p><em>Ki &rsquo;ozen sheme&rsquo;ah vateashereni</em> (for the ear that heard me called me blessed) &mdash; <em>&rsquo;ishar</em> = to pronounce blessed/happy (the same root as the <em>&rsquo;ashrei</em> beatitudes of Ps 1:1; Matt 5:3&ndash;11). <em>Ve&rsquo;ayin ra&rsquo;atah vate&rsquo;ideli</em> = &ldquo;and the eye that saw me testified for me&rdquo; &mdash; both the hearing and seeing of Job&rsquo;s conduct brought forth spontaneous testimony to his righteousness. The two-witness principle of Deut 19:15 (<em>al-pi shnayim &rsquo;edim</em>) is invoked as Job&rsquo;s universal community endorsement.</p>",
    "12": "<p><em>Ki &rsquo;amallet &rsquo;ani meshavea&rsquo;</em> (for I rescued the poor when they cried out) &mdash; <em>amallet</em> = I rescued/delivered (piel of <em>palat</em> = to escape, deliver). <em>&rsquo;ani meshavea&rsquo;</em> = the poor one crying out (<em>shavea&rsquo;</em> from <em>shavac</em> = to cry for help; cf. <em>meshavea&rsquo;</em> in the Psalms as the cry of the oppressed). <em>Veyatom velo-&rsquo;ozer lo</em> = &ldquo;and the fatherless who had no helper&rdquo; &mdash; <em>yatom</em> = orphan (one of the three protected groups in covenant law alongside the widow and stranger, Exod 22:21&ndash;22).</p>",
    "13": "<p><em>Birkat &rsquo;oved &rsquo;alai tavo&rsquo;</em> (the blessing of the one perishing came upon me) &mdash; <em>&rsquo;oved</em> = the one perishing/dying (participle of <em>&rsquo;abad</em> = to perish). The blessing of the dying person &mdash; the final words of a dying man &mdash; is the most precious form of blessing in the ancient world (cf. Jacob&rsquo;s deathbed blessing, Gen 49). Job received these from those he rescued. <em>Velev &rsquo;almanah &rsquo;arnin</em> = &ldquo;and the widow&rsquo;s heart I caused to sing/ring for joy&rdquo; &mdash; <em>&rsquo;arnin</em> (hiphil of <em>ranan</em> = to ring out in joy). The widow is the second of the three protected covenant classes.</p>",
    "14": "<p><em>Tsedaqah lavashti vatilbasheni</em> (I put on righteousness and it clothed me) &mdash; the Hebrew is reflexive: Job clothed himself in <em>tsedaqah</em> (righteousness), and it clothed him in return. The reflexive structure suggests that righteousness is not merely worn like a garment but becomes internalized &mdash; the garment takes possession of the wearer. <em>Kemeil umitsaneph mishpati</em> = &ldquo;my justice was like a robe and turban&rdquo; &mdash; <em>me&rsquo;il</em> = the outer robe (worn by Samuel, 1 Sam 2:19; by the high priest, Lev 8:7; by princes); <em>tsanif</em> = turban/headdress (worn by the high priest, Exod 28:4). The two vestments are priestly and royal &mdash; Job&rsquo;s justice clothed him in the robes of the double office.</p>",
    "15": "<p><em>&rsquo;Einayim hayiti la&rsquo;iver</em> (I was eyes for the blind) &mdash; <em>&rsquo;einayim</em> = eyes. Job&rsquo;s justice function was literally to see on behalf of those who could not see (the blind) &mdash; to represent their interests in legal proceedings. <em>Veraglaim la&rsquo;isser &rsquo;ani</em> = &ldquo;and feet for the lame&rdquo; &mdash; <em>&rsquo;isser</em> = lame (from <em>&rsquo;isar</em> = to be hobbled/lame). The double disability of blindness and lameness appears together in 2 Sam 5:6&ndash;8 (the Jebusites taunting David) and in Isa 35:5&ndash;6 (the messianic restoration). Job personifies the remedying of these disabilities.</p>",
    "16": "<p><em>&rsquo;Av &rsquo;anokhi la&rsquo;evyonim</em> (I was a father to the needy) &mdash; <em>&rsquo;av</em> = father; the patriarchal-protector role taken on behalf of those without a natural advocate. <em>Veriv lo-yadati &rsquo;ehqerehu</em> = &ldquo;and I investigated the case of the one I did not know&rdquo; &mdash; <em>riv</em> = a legal dispute/lawsuit (the same word as the covenant lawsuit form); <em>haqar</em> = to probe/investigate thoroughly. Job not only helped those he knew; he took on the cases of complete strangers, investigating their legal claims.</p>",
    "17": "<p><em>Va&rsquo;ashabbera metsallot &rsquo;avval</em> (I broke the fangs/jaws of the wicked) &mdash; <em>metsallot</em> = jaws, fangs (of a predatory animal); the wicked is a predator with fangs. <em>Shabbera</em> = I broke/shattered (piel). <em>Umishinav &rsquo;ashlikh tered</em> = &ldquo;and from his teeth I forced the prey&rdquo; &mdash; <em>tered</em> = prey (what is torn); Job forcibly extracted the victim from the wicked&rsquo;s grip. The metaphor: Job as the anti-predator, rescuing prey from the jaws of the powerful wicked.</p>",
    "18": "<p><em>Va&rsquo;omar &rsquo;im-qinni &rsquo;egva&rsquo;</em> (then I said &ldquo;in my nest I shall die&rdquo;) &mdash; <em>qen</em> = nest; dying in one&rsquo;s nest = dying at home surrounded by family and comfort, like a bird dying in its nest. The image is of a peaceful, natural, dignified death at the end of a long, productive life. <em>Vekhahol &rsquo;arbeh yamim</em> = &ldquo;and I shall multiply my days like sand&rdquo; &mdash; <em>khahol</em> = sand (the same comparison used for Abraham&rsquo;s promised offspring, Gen 22:17). The expectation of long life, many descendants, peaceful death.</p>",
    "19": "<p><em>Shorshi patua&rsquo; &rsquo;el-mayim</em> (my roots spread out to the water) &mdash; the tree-by-water imagery for righteous prosperity (Ps 1:3; Jer 17:8). <em>Vetal yalin biqtsiri</em> = &ldquo;and the dew rested all night on my branches&rdquo; &mdash; <em>tal</em> = dew (the nightly moisture that kept plants alive in the dry season; a symbol of divine blessing, Gen 27:28; Deut 33:28). Job describes his former life as a well-watered tree, rooted deep and refreshed nightly.</p>",
    "20": "<p><em>Kevodi hadash &rsquo;imadi</em> (my glory was fresh with me) &mdash; <em>kavod</em> = glory/honor/weight (the same word used for YHWH&rsquo;s glory in theophanies). Job&rsquo;s honor was perpetually fresh, not diminishing. <em>Veqashti beyadi tahalif</em> = &ldquo;and my bow was continually renewed in my hand&rdquo; &mdash; the bow as a symbol of military and social power (Gen 49:24, Joseph&rsquo;s bow remains firm; 1 Sam 18:4, Jonathan&rsquo;s bow given to David). A bow &ldquo;renewed&rdquo; is a bow kept at full tension, ready for use.</p>",
    "21": "<p><em>Li shomeu veyehhelu</em> (men listened to me and waited) &mdash; <em>shomeu</em> = they listened (with focused attention, the kind of hearing that leads to action). <em>Vedammu lemodati</em> = &ldquo;and held their silence for my counsel&rdquo; &mdash; <em>damam</em> = to be silent, still (cf. Ps 46:10: &ldquo;be still and know that I am God&rdquo;). The community&rsquo;s posture before Job: attentive silence, waiting for his wisdom.</p>",
    "22": "<p><em>&rsquo;Ahar davari lo yishnnu</em> (after my words they spoke no more) &mdash; Job&rsquo;s words were so comprehensive and authoritative that follow-up discussion was unnecessary. <em>Vetipah &rsquo;alay millatam</em> = &ldquo;and my speech fell upon them&rdquo; &mdash; <em>tipah</em> = to drip/fall (as rain). Job&rsquo;s word falling on people like rain echoes the anticipation of v23 (they waited for him as for rain).</p>",
    "23": "<p><em>Veyihhalu ki-malqosh</em> (they waited for me as for the latter rain) &mdash; <em>malqosh</em> = the spring/latter rain (March-April in Israel, the second rainfall season; the critical late rain that filled the grain). The former rain (<em>yoreh</em>) opens the planting season; the <em>malqosh</em> completes the grain. Job&rsquo;s words were as critically awaited as the spring rain &mdash; without which the entire season&rsquo;s crop would fail. <em>Ufehem patsou limlaqosh</em> = &ldquo;and they opened their mouths wide as for the spring rain&rdquo; &mdash; the gesture of opening the mouth wide to receive falling rain from heaven.</p>",
    "24": "<p><em>&rsquo;Eshoq &rsquo;alehem lo ya&rsquo;aminu</em> (when I smiled they could hardly believe it) &mdash; <em>shoq</em> = to smile, laugh (used of YHWH laughing/mocking in Ps 2:4 and 37:13). Job&rsquo;s smile of approval was so valued that receiving it was almost unbelievable to the recipient. <em>Ve&rsquo;or panay lo yappilu</em> = &ldquo;and the light of my face they did not let fall&rdquo; &mdash; the &ldquo;light of the face&rdquo; is the approval and favor radiating from a leader&rsquo;s expression (Num 6:25: &ldquo;YHWH make his face shine upon you&rdquo;). Job&rsquo;s community treasured his approval as they treasured divine favor.</p>",
    "25": "<p><em>&rsquo;Evchar darkam ve&rsquo;eshev ro&rsquo;sh</em> (I chose the course for them and sat as head/chief) &mdash; <em>ro&rsquo;sh</em> = head, chief (the primary leader). Job&rsquo;s leadership was not just reactive but directive: he chose (<em>bahar</em>) their path. <em>Va&rsquo;eshkon kemayim begedud</em> = &ldquo;I dwelt as a king among his troops&rdquo; &mdash; <em>gedud</em> = a troop/raiding band; the military unit whose king lives among them. Job was not an absent leader but one who lived within his community. <em>Ka&rsquo;asher &rsquo;avelim yenahhem</em> = &ldquo;as one who comforts mourners&rdquo; &mdash; <em>naham</em> = to comfort (the same verb used of the friends&rsquo; mission at 2:11, <em>lenahhamo</em>). The final verse of Job&rsquo;s nostalgic portrait identifies the supreme mark of his former leadership: he comforted those who mourned.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'job')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', 'job', existing)
    total = sum(len(vv) for vv in ORIGINAL.values())
    print(f'Job 27-29 mkt-original: {total} verses written '
          '(' + ', '.join(f'ch{ch}={len(ORIGINAL[ch])}' for ch in sorted(ORIGINAL)) + ').')

if __name__ == '__main__':
    main()
